@startuml
!theme plain

class "Composite" as Composite {
  + add(component:Component):void
  + remove(component:Component):void
  + getChild():int
  + operation():void
}

class "Leaf" as Leaf {
  + operation():void
}

class "Component" as Component {
  + add(component:Component):void
  + remove(component:Component):void
  + getChild():int
  + operation():void
}

class "Client" as Client {
}

class "OrganizationComponent" as OrganizationComponent {
  + add(component:OrganizationComponent):void
  + print():void
}

class "University" as University {
}

class "College" as College {
}

class "Department" as Department {
}

note left of Composite
  组合可以操作子节点或者叶子节点，但可能不具有叶子节点的某些行为
end note

note right of Leaf
  叶子节点，不能操作子节点
end note

note left of Component
  Component 为所有节点的基类，不管是普通节点还是叶子节点
end note

Composite --|> Component : extends
Composite o-- Component : contains
Leaf --|> Component : extends
Client ..> OrganizationComponent : uses
OrganizationComponent <|-- University
OrganizationComponent <|-- College
OrganizationComponent <|-- Department
University o-- OrganizationComponent : contains
College o-- OrganizationComponent : contains
Department o-- OrganizationComponent : contains

@enduml
